WebLink.url:
var oppstage = "{!Opportunity.StageName}";
if( oppstage == "Closed Won" || oppstage == "Closed Lost")
{alert ("You cannot update a closed opportunity, please contact SalesOps for assistance.");
}
else
{

var OpportunityID = "{!Opportunity.ID__c}" ;
var CurrentUser = "{!$User.Id}" ;
var Close = "Lost" ;

var url = "/flow/Close_opportunity?&VarOpportunityID="+OpportunityID;
url= url + "&VarCurrentUser="+CurrentUser;
url= url + "&VarClose="+Close +"&retURL=/"+OpportunityID;


window.parent.location= url;
}
